class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        special_count = 0
        for c in set(word.lower()):
            lower_idx = word.lower().index(c)
            upper_idx = float('inf')
            for i, char in enumerate(word):
                if char.lower() == c:
                    if char.isupper():
                        upper_idx = min(upper_idx, i)
                    else:
                        lower_idx = max(lower_idx, i)
            if lower_idx < upper_idx:
                special_count += 1
        return special_count
